function calculate(expression) {
  const tokens = expression.split(/[+*/-]/);
  let result = 0;

  for (let i = 0; i < tokens.length; i++) {
    if (tokens[i] === '+') {
      result += Number(tokens[i - 1]);
    } else if (tokens[i] === '-') {
      result -= Number(tokens[i - 1]);
    } else if (tokens[i] === '*') {
      result *= Number(tokens[i - 1]);
    } else if (tokens[i] === '/') {
      result /= Number(tokens[i - 1]);
    }
  }

  return result;
}

// Call the function with a test expression
console.log(calculate('2+3*4'));

